a.code:
// Install deps
npm install        // ~8s

// Start server
node server.ts     // needs tsx

// Run tests
npx jest           // ~4s startup

b.code:
// Install deps
bun install        // ~0.5s

// Start server
bun server.ts      // native TS

// Run tests
bun test           // ~0.2s startup

slides.code:
// npm install (fresh, 50 deps)
Node: npm install    →  8.2s
Bun:  bun install    →  0.4s  (20x)

// TypeScript execution
Node: npx tsx app.ts →  1.1s
Bun:  bun app.ts     →  0.05s (22x)

// HTTP server (req/sec)
Node: express        →  15K/s
Bun:  Bun.serve      →  120K/s (8x)

// Test suite (100 tests)
Node: jest           →  4.2s
Bun:  bun test       →  0.3s  (14x)
